/**
 * Check if an IP address is in a private/internal/reserved range
 */
function isPrivateIP(ip) {
  // Normalize IPv4-mapped IPv6 addresses
  let normalizedIP = ip;
  if (normalizedIP.startsWith('::ffff:')) {
    normalizedIP = normalizedIP.substring(7);
  }

  // IPv4 checks
  if (net.isIPv4(normalizedIP)) {
    const parts = normalizedIP.split('.').map(Number);
    const [a, b, c, d] = parts;

    // 0.0.0.0/8 - Current network
    if (a === 0) return true;

    // 10.0.0.0/8 - Private
    if (a === 10) return true;

    // 100.64.0.0/10 - Carrier-grade NAT
    if (a === 100 && b >= 64 && b <= 127) return true;

    // 127.0.0.0/8 - Loopback
    if (a === 127) return true;

    // 169.254.0.0/16 - Link-local
    if (a === 169 && b === 254) return true;

    // 172.16.0.0/12 - Private
    if (a === 172 && b >= 16 && b <= 31) return true;

    // 192.0.0.0/24 - IETF Protocol Assignments
    if (a === 192 && b === 0 && c === 0) return true;

    // 192.0.2.0/24 - TEST-NET-1
    if (a === 192 && b === 0 && c === 2) return true;

    // 192.88.99.0/24 - 6to4 Relay Anycast
    if (a === 192 && b === 88 && c === 99) return true;

    // 192.168.0.0/16 - Private
    if (a === 192 && b === 168) return true;

    // 198.18.0.0/15 - Benchmark testing
    if (a === 198 && (b === 18 || b === 19)) return true;

    // 198.51.100.0/24 - TEST-NET-2
    if (a === 198 && b === 51 && c === 100) return true;

    // 203.0.113.0/24 - TEST-NET-3
    if (a === 203 && b === 0 && c === 113) return true;

    // 224.0.0.0/4 - Multicast
    if (a >= 224 && a <= 239) return true;

    // 240.0.0.0/4 - Reserved for future use
    if (a >= 240) return true;

    // AWS metadata endpoint
    if (normalizedIP === '169.254.169.254') return true;

    // GCP metadata endpoint
    if (normalizedIP === '169.254.169.253') return true;

    return false;
  }

  // IPv6 checks
  if (net.isIPv6(normalizedIP)) {
    const lower = normalizedIP.toLowerCase();

    // Loopback ::1
    if (lower === '::1' || lower === '0000:0000:0000:0000:0000:0000:0000:0001') return true;

    // Unspecified ::
    if (lower === '::' || lower === '0000:0000:0000:0000:0000:0000:0000:0000') return true;

    // Link-local fe80::/10
    if (lower.startsWith('fe80')) return true;

    // Unique local fc00::/7
    if (lower.startsWith('fc') || lower.startsWith('fd')) return true;

    // Multicast ff00::/8
    if (lower.startsWith('ff')) return true;

    // IPv4-mapped IPv6 ::ffff:0:0/96 - check the embedded IPv4
    if (lower.startsWith('::ffff:')) {
      const embeddedIPv4 = lower.substring(7);
      if (net.isIPv4(embeddedIPv4)) {
        return isPrivateIP(embeddedIPv4);
      }
    }

    return false;
  }

  // If we can't determine the IP type, block it
  return true;
}

/**
 * Validate and parse the target URL
 */
function validateURL(urlString) {
  let parsed;
  try {
    parsed = new URL(urlString);
  } catch (e) {
    throw new Error('Invalid URL format');
  }

  // Only allow http and https
  if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
    throw new Error(`Disallowed protocol: ${parsed.protocol}`);
  }

  // Block URLs with credentials
  if (parsed.username || parsed.password) {
    throw new Error('URLs with embedded credentials are not allowed');
  }

  // Check domain against allowlist
  const hostname = parsed.hostname.toLowerCase();
  if (!ALLOWED_DOMAINS.has(hostname)) {
    throw new Error(`Domain not in allowlist: ${hostname}`);
  }

  // Block IP addresses used directly as hostnames
  if (net.isIPv4(hostname) || net.isIPv6(hostname)) {
    throw new Error('Direct IP addresses are not allowed; use domain names');
  }

  return parsed;
}

/**
 * Resolve hostname and verify all resolved IPs are public
 */
function resolveAndValidate(hostname) {
  return new Promise((resolve, reject) => {
    dns.lookup(hostname, { all: true }, (err, addresses) => {
      if (err) {
        return reject(new Error(`DNS resolution failed for ${hostname}: ${err.message}`));
      }

      if (!addresses || addresses.length === 0) {
        return reject(new Error(`No DNS records found for ${hostname}`));
      }

      for (const addr of addresses) {
        if (isPrivateIP(addr.address)) {
          return reject(
            new Error(`Resolved IP ${addr.address} for ${hostname} is in a private/reserved range`)
          );
        }
      }

      resolve(addresses);
    });
  });
}

/**
 * Make an HTTP/HTTPS request with controlled redirect handling
 */
function makeRequest(targetURL, method, headers, body, redirectCount = 0) {
  return new Promise(async (resolve, reject) => {
    let parsed;
    try {
      parsed = validateURL(targetURL);
    } catch (e) {
      return reject(e);
    }

    // DNS resolution and IP validation
    try {
      await resolveAndValidate(parsed.hostname);
    } catch (e) {
      return reject(e);
    }

    const isHTTPS = parsed.protocol === 'https:';
    const transport = isHTTPS ? https : http;

    // Build request options
    const requestOptions = {
      hostname: parsed.hostname,
      port: parsed.port || (isHTTPS ? 443 : 80),
      path: parsed.pathname + parsed.search,
      method: method || 'POST',
      headers: {
        ...sanitizeHeaders(headers),
        Host: parsed.hostname,
      },
      timeout: REQUEST_TIMEOUT,
      // Do NOT follow redirects automatically
      maxRedirects: 0,
    };

    const req = transport.request(requestOptions, (res) => {
      const statusCode = res.statusCode;

      // Handle redirects manually with strict validation
      if (statusCode >= 300 && statusCode < 400 && res.headers.location) {
        if (redirectCount >= MAX_REDIRECTS) {
          return reject(new Error(`Maximum redirects (${MAX_REDIRECTS}) exceeded`));
        }

        let redirectURL;
        try {
          // Resolve relative redirects against the current URL
          redirectURL = new URL(res.headers.location, targetURL).toString();
        } catch (e) {
          return reject(new Error(`Invalid redirect URL: ${res.headers.location}`));
        }

        // Validate the redirect target through the same checks
        // (validateURL + DNS resolution + IP check will run again)
        return makeRequest(redirectURL, method, headers, body, redirectCount + 1)
          .then(resolve)
          .catch(reject);
      }

      // Collect response body with size limit
      const chunks = [];
      let totalSize = 0;

      res.on('data', (chunk) => {
        totalSize += chunk.length;
        if (totalSize > MAX_RESPONSE_SIZE) {
          req.destroy();
          return reject(new Error('Response size exceeds maximum allowed'));
        }
        chunks.push(chunk);
      });

      res.on('end', () => {
        const responseBody = Buffer.concat(chunks);
        resolve({
          statusCode: res.statusCode,
          headers: res.headers,
          body: responseBody,
        });
      });

      res.on('error', (err) => {
        reject(new Error(`Response error: ${err.message}`));
      });
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timed out'));
    });

    req.on('error', (err) => {
      reject(new Error(`Request error: ${err.message}`));
    });

    // Send body if present
    if (body) {
      const bodyData = typeof body === 'string' ? body : JSON.stringify(body);
      req.write(bodyData);
    }

    req.end();
  });
}

/**
 * Sanitize outbound headers - remove sensitive/dangerous headers
 */
function sanitizeHeaders(headers) {
  if (!headers || typeof headers !== 'object') return {};

  const BLOCKED_HEADERS = new Set([
    'host',
    'connection',
    'keep-alive',
    'transfer-encoding',
    'te',
    'upgrade',
    'proxy-authorization',
    'proxy-connection',
    'x-forwarded-for',
    'x-forwarded-host',
    'x-forwarded-proto',
    'x-real-ip',
    'forwarded',
    'cookie',
    'set-cookie',
    'authorization', // Don't forward our auth; user should set target auth explicitly
  ]);

  const sanitized = {};
  for (const [key, value] of Object.entries(headers)) {
    const lowerKey = key.toLowerCase();
    if (!BLOCKED_HEADERS.has(lowerKey)) {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

/**
 * Sanitize response headers before forwarding back to the client
 */
function sanitizeResponseHeaders(headers) {
  if (!headers || typeof headers !== 'object') return {};

  const BLOCKED_RESPONSE_HEADERS = new Set([
    'set-cookie',
    'transfer-encoding',
    'connection',
    'keep-alive',
    'proxy-authenticate',
    'proxy-authorization',
    'te',
    'trailer',
    'upgrade',
  ]);

  const sanitized = {};
  for (const [key, value] of Object.entries(headers)) {
    const lowerKey = key.toLowerCase();
    if (!BLOCKED_RESPONSE_HEADERS.has(lowerKey)) {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

