app.post('/proxy', async (req, res) => {
  const { url, method, headers: customHeaders, body: requestBody } = req.body;

  if (!url) {
    return res.status(400).json({ error: 'Missing required field: url' });
  }

  if (typeof url !== 'string') {
    return res.status(400).json({ error: 'URL must be a string' });
  }

  // Validate method if provided
  const allowedMethods = new Set(['GET', 'POST', 'PUT', 'PATCH', 'DELETE']);
  const requestMethod = (method || 'POST').toUpperCase();
  if (!allowedMethods.has(requestMethod)) {
    return res.status(400).json({ error: `Disallowed HTTP method: ${requestMethod}` });
  }

  try {
    console.log(`[PROXY] ${requestMethod} ${url}`);

    const result = await makeRequest(url, requestMethod, customHeaders, requestBody);

    // Forward sanitized response headers
    const safeHeaders = sanitizeResponseHeaders(result.headers);
    for (const [key, value] of Object.entries(safeHeaders)) {
      res.setHeader(key, value);
    }

    res.status(result.statusCode).send(result.body);
  } catch (err) {
    console.error(`[PROXY ERROR] ${err.message}`);

    // Don't leak internal details in error messages
    const safeErrors = [
      'Invalid URL format',
      'Disallowed protocol',
      'URLs with embedded credentials are not allowed',
      'Domain not in allowlist',
      'Direct IP addresses are not allowed; use domain names',
      'Maximum redirects',
      'Request timed out',
      'Response size exceeds maximum allowed',
    ];

    const isSafeError = safeErrors.some((prefix) => err.message.startsWith(prefix));

    if (isSafeError) {
      return res.status(400).json({ error: err.message });
    }

    if (err.message.includes('private/reserved range')) {
      return res.status(403).json({ error: 'Target resolves to a blocked IP range' });
    }

    if (err.message.includes('DNS resolution failed')) {
      return res.status(502).json({ error: 'Could not resolve target hostname' });
    }

    return res.status(502).json({ error: 'Failed to proxy request to target' });
  }
});

